@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div id="@_wrapperId" class="@PositionClass @Class" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @if (_isOpen)
    {
        <div id="@_contentId" role="menu" aria-orientation="@MenuOrientation" aria-label="@L["Common.Actions"]" class="@ItemsContainerClass">
            @foreach (var item in Items)
            {
                <div class="@(Cx.Join("flex", Cx.When(Direction == SpeedDialDirection.Left || Direction == SpeedDialDirection.Right, "flex-col"), "items-center gap-2", Cx.When(Direction == SpeedDialDirection.Right || Direction == SpeedDialDirection.Down, "flex-row-reverse")))">
                    @* Label is decorative here — the action button carries the
                       accessible name via aria-label, so hide the visual span. *@
                    <span class="whitespace-nowrap rounded-md bg-popover border border-border/40 px-2 py-1 text-xs text-popover-foreground shadow-md" aria-hidden="true">
                        @item.Label
                    </span>
                    <Tooltip>
                        <TooltipTrigger AsChild>
                            <ChildContentSlot Context="slot">
                                <button type="button"
                                        role="menuitem"
                                        class="flex h-10 w-10 cursor-pointer items-center justify-center rounded-full bg-secondary text-secondary-foreground shadow-md transition-all hover:bg-secondary/80 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed"
                                        @onclick="() => HandleItemClick(item)"
                                        disabled="@item.Disabled"
                                        aria-label="@item.Label"
                                        @attributes="slot.Attributes">
                                    @if (!string.IsNullOrEmpty(item.Icon))
                                    {
                                        <span class="text-sm">@item.Icon</span>
                                    }
                                </button>
                            </ChildContentSlot>
                        </TooltipTrigger>
                        <TooltipContent>@item.Label</TooltipContent>
                    </Tooltip>
                </div>
            }
        </div>
    }

    <button id="@_triggerId"
            type="button"
            class="@TriggerClass"
            @onclick="ToggleOpen"
            aria-expanded="@(_isOpen ? "true" : "false")"
            aria-haspopup="menu"
            aria-label="@L["Common.Actions"]"
            disabled="@Disabled">
        @if (!string.IsNullOrEmpty(Icon))
        {
            <span class="@(Cx.Join("text-xl leading-none transition-transform", Cx.When(_isOpen, "rotate-45")))">@Icon</span>
        }
        else
        {
            var plusClass = Cx.Join("h-6 w-6 transition-transform", Cx.When(_isOpen, "rotate-45"));
            <Blazicon Svg="Lucide.Plus" class="@plusClass" />
        }
    </button>
</div>

@inject IComponentInteropService Interop

@code {
    [Parameter] public List<SpeedDialItem> Items { get; set; } = new();
    /// <summary>Optional trigger icon override (text/emoji, like
    /// <see cref="SpeedDialItem.Icon"/>). When unset, a Lucide plus icon
    /// that rotates into an × while open is rendered.</summary>
    [Parameter] public string? Icon { get; set; }
    [Parameter] public SpeedDialPosition Position { get; set; } = SpeedDialPosition.BottomRight;
    [Parameter] public SpeedDialDirection Direction { get; set; } = SpeedDialDirection.Up;
    /// <summary>Trigger color variant following the Button variant names:
    /// "Default" (primary), "Secondary", "Destructive", "Outline", "Ghost".</summary>
    [Parameter] public string Variant { get; set; } = "Default";
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = LumeoIds.New("speeddial");
    private readonly string _contentId = LumeoIds.New("speeddial-content");
    private readonly string _triggerId = LumeoIds.New("speeddial-trigger");
    private bool _isOpen;
    private bool _registered;
    private int _focusedIndex = -1;

    // The action menu is laid out vertically for Up/Down directions and
    // horizontally for Left/Right.
    private string MenuOrientation =>
        Direction is SpeedDialDirection.Left or SpeedDialDirection.Right ? "horizontal" : "vertical";

    private string PositionClass => Position switch
    {
        SpeedDialPosition.BottomLeft => "fixed bottom-6 start-6 z-50 flex flex-col-reverse items-start",
        SpeedDialPosition.TopRight => "fixed top-6 end-6 z-50 flex flex-col items-end",
        SpeedDialPosition.TopLeft => "fixed top-6 start-6 z-50 flex flex-col items-start",
        _ => "fixed bottom-6 end-6 z-50 flex flex-col-reverse items-end"
    };

    private string ItemsContainerClass
    {
        get
        {
            var directionClass = Direction switch
            {
                SpeedDialDirection.Down => "flex flex-col mt-2",
                SpeedDialDirection.Left => "flex flex-row-reverse me-2",
                SpeedDialDirection.Right => "flex flex-row ms-2",
                _ => "flex flex-col-reverse mb-2"
            };
            return $"{directionClass} gap-2 animate-fade-in";
        }
    }

    // Variant color classes mirror Button.ButtonVariant conventions.
    private string TriggerVariantClass => Variant?.ToLowerInvariant() switch
    {
        "secondary" => "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        "destructive" => "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        "outline" => "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        "ghost" => "hover:bg-accent hover:text-accent-foreground",
        _ => "bg-primary text-primary-foreground hover:bg-primary/90"
    };

    private string TriggerClass =>
        Disabled
            ? Cx.Join("flex h-14 w-14 cursor-not-allowed items-center justify-center rounded-full shadow-lg opacity-50 pointer-events-none", TriggerVariantClass)
            : Cx.Join("flex h-14 w-14 cursor-pointer items-center justify-center rounded-full shadow-lg transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2", TriggerVariantClass);

    private async Task ToggleOpen()
    {
        if (Disabled) return;
        if (_isOpen)
            await Close();
        else
            await Open();
    }

    private async Task Open()
    {
        _isOpen = true;
        _focusedIndex = -1;
        StateHasChanged();
        await Task.Yield();
        await Interop.RegisterClickOutside(_wrapperId, null, async () =>
        {
            await Close();
            await InvokeAsync(StateHasChanged);
        });
        _registered = true;

        // Move focus to the first action so arrow keys work immediately and
        // keyboard users land inside the menu (MUI SpeedDial behaviour).
        var count = await Interop.GetMenuItemCount(_contentId);
        if (count > 0)
        {
            _focusedIndex = 0;
            try { await Interop.FocusMenuItemByIndex(_contentId, 0); } catch (JSDisconnectedException) { }
        }
    }

    private async Task Close(bool restoreFocus = false)
    {
        _isOpen = false;
        _focusedIndex = -1;
        if (_registered)
        {
            try { await Interop.UnregisterClickOutside(_wrapperId); }
            catch (JSDisconnectedException) { }
            _registered = false;
        }
        if (restoreFocus)
        {
            try { await Interop.FocusElement(_triggerId); } catch (JSDisconnectedException) { }
        }
    }

    // MUI SpeedDial keyboard model: arrows move between actions, Escape closes
    // and returns focus to the trigger, Enter/Space/ArrowUp/ArrowDown open the
    // menu from the (focused) trigger.
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (Disabled) return;

        if (!_isOpen)
        {
            // From the trigger: open on activation / arrow into the menu.
            if (e.Key is "Enter" or " " or "ArrowUp" or "ArrowDown" or "ArrowLeft" or "ArrowRight")
            {
                await Open();
            }
            return;
        }

        switch (e.Key)
        {
            case "Escape":
                await Close(restoreFocus: true);
                break;
            case "ArrowDown":
            case "ArrowRight":
                await MoveFocus(1);
                break;
            case "ArrowUp":
            case "ArrowLeft":
                await MoveFocus(-1);
                break;
            case "Home":
                await FocusIndex(0);
                break;
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(_contentId);
                    if (count > 0) await FocusIndex(count - 1);
                    break;
                }
        }
    }

    private async Task MoveFocus(int delta)
    {
        var count = await Interop.GetMenuItemCount(_contentId);
        if (count <= 0) return;
        _focusedIndex = ((_focusedIndex < 0 ? 0 : _focusedIndex) + delta % count + count) % count;
        try { await Interop.FocusMenuItemByIndex(_contentId, _focusedIndex); } catch (JSDisconnectedException) { }
    }

    private async Task FocusIndex(int index)
    {
        _focusedIndex = index;
        try { await Interop.FocusMenuItemByIndex(_contentId, index); } catch (JSDisconnectedException) { }
    }

    private async Task HandleItemClick(SpeedDialItem item)
    {
        if (Disabled || item.Disabled) return;
        await item.OnClick.InvokeAsync();
        await Close(restoreFocus: true);
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered)
        {
            try { await Interop.UnregisterClickOutside(_wrapperId); }
            catch (JSDisconnectedException) { }
        }
    }

    public class SpeedDialItem
    {
        public string Label { get; set; } = "";
        public string? Icon { get; set; }
        public EventCallback OnClick { get; set; }
        public bool Disabled { get; set; }
    }

    public enum SpeedDialPosition { BottomRight, BottomLeft, TopRight, TopLeft }
    public enum SpeedDialDirection { Up, Down, Left, Right }
}
